const StatCards = ({ orders }) => {
    const pending = orders.filter(o => o.status === "Pending").length;
    const shipped = orders.filter(o => o.status === "Shipped").length;
    const delivered = orders.filter(o => o.status === "Delivered").length;
    const urgent = orders.filter(o => o.urgency === 5).length;

    return (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '20px', padding: '20px' }}>
            <div style={{ background: '#FFD700', padding: '20px', borderRadius: '10px' }}>
                <h3>To be Picked</h3>
                <h2>{pending}</h2>
            </div>
            <div style={{ background: '#3498db', padding: '20px', borderRadius: '10px', color: '#fff' }}>
                <h3>Shipped</h3>
                <h2>{shipped}</h2>
            </div>
            <div style={{ background: '#2ecc71', padding: '20px', borderRadius: '10px', color: '#fff' }}>
                <h3>Delivered</h3>
                <h2>{delivered}</h2>
            </div>
            <div style={{ background: '#e74c3c', padding: '20px', borderRadius: '10px', color: '#fff' }}>
                <h3>High Urgency</h3>
                <h2>{urgent}</h2>
            </div>
        </div>
    );
};

export default StatCards;
